fun isCyclicRotation(A: LongArray, B: LongArray): Boolean {
    val k = A.size
    if (k == 0) return true
    if (k == 1) return A[0] == B[0]

    // Check if B matches any rotation of A
    for (start in 0 until k) {
        var match = true
        for (i in 0 until k) {
            if (B[i] != A[(start + i) % k]) {
                match = false
                break
            }
        }
        if (match) return true
    }
    return false
