// Helper function to check if T is a cyclic rotation of A, assuming |A| == |T| = k.
// This checks if there exists a shift j such that T matches A rotated left by j positions.
fun isRotation(A: LongArray, T: LongArray): Boolean {
    val k = A.size
    if (k == 0) return true
    if (k == 1) return A[0] == T[0]

    // Check all k possible shifts j (0 <= j < k)
    for (j in 0 until k) {
        var matches = true
        for (m in 0 until k) {
            // T[m] must equal the element of A that ends up at position m after j left shifts.
            // This element was originally at index (m + j) % k in A.
            val originalIndex = (m + j) % k
            if (T[m] != A[originalIndex]) {
                matches = false
                break
            }
        }
        if (matches) return true
    }
    return false
}

