fun computeLPS(pattern: Array<Long>): IntArray {
    val M = pattern.size
    val lps = IntArray(M)
    var length = 0 // length of the previous longest prefix suffix
    var i = 1
    while (i < M) {
        if (pattern[i] == pattern[length]) {
            length++
            lps[i] = length
            i++
        } else {
            if (length != 0) {
                length = lps[length - 1]
            } else {
                lps[i] = 0
                i++
            }
        }
    }
    return lps
}

fun KMPSearch(text: Array<Long>, pattern: Array<Long>): Boolean {
    val N = text.size
    val M = pattern.size
    if (M == 0) return true
    if (N < M) return false

    val lps = computeLPS(pattern)

    var i = 0 // index for text
    var j = 0 // index for pattern

    while (i < N) {
        if (pattern[j] == text[i]) {
            i++
            j++
        }
        if (j == M) {
            // Found a match
            return true
        } else if (i < N && pattern[j] != text[i]) {
            if (j != 0) {
                j = lps[j - 1]
            } else {
                i++
            }
        }
    }
    return false
}

fun isCyclicPermutation(A: Array<Long>, B: Array<Long>): Boolean {
    val k = A.size
    if (k == 0) return true

    if (k == 1) return true

    // Construct T = A + A. We need T to be an Array<Long>
    val TA = Array(2 * k) { 0L }
    for (i in 0 until k) {
        TA[i] = A[i]
        TA[i + k] = A[i]
    }

    // Search for B in TA.
    return KMPSearch(TA, B)
}


